mapper.select:
select p.id, p.name, p.category_id as categoryId, c.name as categoryName, p.breed, p.age, p.gender, p.price, p.stock, p.cover_url as coverUrl, p.description, p.health_status as healthStatus, p.vaccine_info as vaccineInfo, p.status, p.create_time as createTime from pet p left join category c on p.category_id = c.id
p.is_deleted = 0
and p.name like concat('%', #{name}, '%')
and p.category_id = #{categoryId}
and p.status = #{status}
order by p.create_time desc

mapper.update:
update pet
set status = #{status}
where id = #{id}
  and is_deleted = 0
